const getFulfillmentItemsForOrder = `-- name: GetFulfillmentItemsForOrder :many
SELECT
    item_id,
    reward_type,
    quantity,
    scale,
    duration_unit
FROM payment_order_item
WHERE order_id = $1
ORDER BY item_id
`

type GetFulfillmentItemsForOrderRow struct {
	ItemID       string                           `json:"item_id"`
	RewardType   PaymentOrderItemRewardType       `json:"reward_type"`
	Quantity     int64                            `json:"quantity"`
	Scale        int16                            `json:"scale"`
	DurationUnit NullPaymentOrderItemDurationUnit `json:"duration_unit"`
}

func (q *Queries) GetFulfillmentItemsForOrder(ctx context.Context, orderID int64) ([]GetFulfillmentItemsForOrderRow, error) {
	rows, err := q.query(ctx, q.getFulfillmentItemsForOrderStmt, getFulfillmentItemsForOrder, orderID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []GetFulfillmentItemsForOrderRow
	for rows.Next() {
		var i GetFulfillmentItemsForOrderRow
		if err := rows.Scan(
			&i.ItemID,
			&i.RewardType,
			&i.Quantity,
			&i.Scale,
			&i.DurationUnit,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Close(); err != nil {
		return nil, err
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

